5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 1.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	};
13	
14	function roundUpToWholeG(amount: number): number {
15	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
16	  return Math.ceil(Math.round(amount * 100) / 100);
17	}
18	
19	export function quote(
20	  _customer: { yearsWithMHPCO: number },
21	  items: Item[],
22	  _previousContracts?: number,
23	): number {
24	  if (items.length === 0) return PROCESSING_FEE;
25	  const basePremium = BASE_PREMIUMS[items[0].type];
26	  const premium = roundUpToWholeG(basePremium * FIRST_INSURANCE_SURCHARGE);
27	  return premium + PROCESSING_FEE;
28	}
29	
30	export function claim(): number {
31	  return undefined as unknown as number;
32	}
